cd /Users/justinrich/Projects/LaneShadow/.kb-run/worktrees/ALIGN-02-android && node <<'NODE'
const fs = require('node:fs');
const path = require('node:path');
const crypto = require('node:crypto');
const worktree = process.cwd();
const ROOT = path.join(worktree, 'tokens');
const SEMANTIC_DIR = path.join(ROOT, 'semantic');
const FONTS_MANIFEST = path.join(ROOT, 'fonts', 'manifest.json');
const THEME_LIGHT_PATH = path.join(ROOT, '..', '.spec', 'design', 'system', 'tokens', 'theme.light.json');
const THEME_DARK_PATH = path.join(ROOT, '..', '.spec', 'design', 'system', 'tokens', 'theme.dark.json');
const tokenFiles = ['typography.tokens.json','colors.tokens.json','dimensions.tokens.json','motion.tokens.json','icons.json','mapbox.tokens.json'];
const tokens = {};
for (const file of tokenFiles) {
  const content = JSON.parse(fs.readFileSync(path.join(SEMANTIC_DIR, file), 'utf8'));
  if (file === 'mapbox.tokens.json') tokens.mapbox = content.map; else Object.assign(tokens, content);
}
const icons = JSON.parse(fs.readFileSync(path.join(SEMANTIC_DIR, 'icons.json'), 'utf8')).icons || [];
const fonts = JSON.parse(fs.readFileSync(FONTS_MANIFEST, 'utf8'));
const hashFor = (tokenData) => {
  const hash = crypto.createHash('sha256');
  hash.update(JSON.stringify({ tokens: tokenData, icons, fonts }));
  for (const filePath of [THEME_LIGHT_PATH, THEME_DARK_PATH]) {
    hash.update(filePath);
    hash.update(fs.readFileSync(filePath, 'utf8'));
  }
  return hash.digest('hex').slice(0, 8);
};
console.log(JSON.stringify({ before: hashFor(tokens), afterColorEdit: hashFor({ ...tokens, color: { ...tokens.color, surface: { ...tokens.color.surface, primary: { ...tokens.color.surface.primary, light: '#000000' } } } }) }, null, 2));
